/// Build a 3×3 shear operator from (row, col, epsilon_numer, epsilon_denom).
/// A = I + (n/d) × E_{row,col}, A⁻¹ = I - (n/d) × E_{row,col}.
fn shear_from_entry(row: usize, col: usize, numer: i16, denom: u16, dim: usize, id: usize) -> Operator {
    let eps = Q::new(BigInt::from(numer as i64), BigInt::from(denom as u64));
    let neg_eps = -eps.clone();

    let mut mat = vec![vec![Q::zero(); dim]; dim];
    let mut inv = vec![vec![Q::zero(); dim]; dim];
    for k in 0..dim {
        mat[k][k] = Q::one();
        inv[k][k] = Q::one();
    }
    mat[row][col] = eps;
    inv[row][col] = neg_eps;

    Operator { id, matrix: mat, matrix_inv: inv, det_sign_positive: true }
}

/// Build a full operator from 9 entries (n×n matrix perturbation on identity).
/// Each entry is (numer, denom) added to I. Uses general n×n inverse.
fn operator_from_entries(entries: &[(i16, u16); 9], dim: usize, id: usize) -> Option<Operator> {
    if dim * dim > entries.len() { return None; }

    let mut mat = vec![vec![Q::zero(); dim]; dim];
    for i in 0..dim {
        for j in 0..dim {
            let idx = i * dim + j;
            let (n, d) = entries[idx];
            let val = Q::new(BigInt::from(n as i64), BigInt::from(d as u64));
            if i == j {
                mat[i][j] = Q::one() + &val;
            } else {
                mat[i][j] = val;
            }
        }
    }

    // General n×n inverse via Gauss-Jordan
    let inv = crate::matrix::invert(&mat)?;
    let d = crate::matrix::det(&mat);
    if d <= Q::zero() { return None; }

    Some(Operator { id, matrix: mat, matrix_inv: inv, det_sign_positive: true })
}

